const content = $input.first().json.content[0].text;
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = { score: 'Warm', reason: 'AI parse error - manual review needed', intent: 'Unknown' }; }
const lead = $('Validate Fields').first().json;
return [{ json: { ...lead, score: parsed.score, reason: parsed.reason, intent: parsed.intent, qualified_at: new Date().toISOString() } }];

const data = $input.first().json;
const phone = data.phone;
if (!phone) {
  return [{ json: { ...data, sms_status: 'skipped_no_phone' } }];
}
const accountSid = $env.TWILIO_ACCOUNT_SID;
const authToken = $env.TWILIO_AUTH_TOKEN;
const messagingServiceSid = $env.TWILIO_MESSAGING_SERVICE_SID;
const msgBody = 'Bonjour ' + data.name + ', merci pour votre interet ! Notre equipe vous contacte sous 60 min. Reservez : https://cal.com/webmind';
const auth = Buffer.from(accountSid + ':' + authToken).toString('base64');
const result = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://api.twilio.com/2010-04-01/Accounts/' + accountSid + '/Messages.json',
  headers: {
    'Authorization': 'Basic ' + auth,
    'Content-Type': 'application/x-www-form-urlencoded'
  },
  body: 'MessagingServiceSid=' + encodeURIComponent(messagingServiceSid) + '&To=' + encodeURIComponent(phone) + '&Body=' + encodeURIComponent(msgBody)
});
return [{ json: { ...data, sms_sid: result.sid, sms_status: result.status } }];

